import{c as t,Q as i,j as a,m as n}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"Runcam WiFiLink v2 — Specs and Setup","description":"Guide for connecting, configuring and using the Runcam WiFiLink v2 camera for a digital FPV system.","frontmatter":{"title":"Runcam WiFiLink v2 — Specs and Setup","description":"Guide for connecting, configuring and using the Runcam WiFiLink v2 camera for a digital FPV system.","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/en/hardware/vtx/runcamwifilinkv2"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/hardware/vtx/runcamwifilinkv2"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/hardware/vtx/runcamwifilinkv2"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/hardware/vtx/runcamwifilinkv2"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/en/hardware/vtx/runcamwifilinkv2"}],["meta",{"property":"og:title","content":"Runcam WiFiLink v2 — Specs and Setup"}],["meta",{"property":"og:description","content":"Guide for connecting, configuring and using the Runcam WiFiLink v2 camera for a digital FPV system."}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-hardware.png"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:locale:alternate","content":"uk_UA"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-hardware.png"}],["meta",{"name":"twitter:title","content":"Runcam WiFiLink v2 — Specs and Setup"}],["meta",{"name":"twitter:description","content":"Guide for connecting, configuring and using the Runcam WiFiLink v2 camera for a digital FPV system."}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://openfpv.com.ua/en/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Hardware\\",\\"item\\":\\"https://openfpv.com.ua/en/hardware/vtx/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Runcam WiFiLink v2 — Specs and Setup\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Runcam WiFiLink v2 — Specs and Setup\\",\\"description\\":\\"Guide for connecting, configuring and using the Runcam WiFiLink v2 camera for a digital FPV system.\\",\\"inLanguage\\":\\"en-US\\",\\"url\\":\\"https://openfpv.com.ua/en/hardware/vtx/runcamwifilinkv2\\",\\"image\\":\\"https://openfpv.com.ua/og-hardware.png\\",\\"dateModified\\":\\"2026-05-31T11:48:56.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"en/hardware/vtx/runcamwifilinkv2.md","filePath":"en/hardware/vtx/runcamwifilinkv2.md","lastUpdated":1780228136000}'),r={name:"en/hardware/vtx/runcamwifilinkv2.md"};function o(l,e,c,d,s,p){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="runcam-wifilink-2" tabindex="-1">Runcam WiFiLink 2 <a class="header-anchor" href="#runcam-wifilink-2" aria-label="Permalink to &quot;Runcam WiFiLink 2&quot;">​</a></h1><p><img src="https://raw.githubusercontent.com/OpenIPC/docs/refs/heads/main/src/assets/images/runcam-wifilink-v2-main-photo.png" alt="main photo" width="400px"></p><h3 id="specifications" tabindex="-1">Specifications <a class="header-anchor" href="#specifications" aria-label="Permalink to &quot;Specifications&quot;">​</a></h3><ul><li>Image Sensor: Sony IMX415</li><li>Field of View (FOV): 160°</li><li>Power Input: DC 9–22V (BEC recommended; direct LiPo connection not recommended)</li><li>Lens Module Size: 19×19 mm (M12), MIPI cable 130 mm (proprietary)</li><li>Mounting Hole Spacing: 25.5×25.5 mm</li><li>Board Size: 30.6×33 mm</li><li>Weight: 30 g (with fan) / 25 g (without fan)</li><li>Antenna Connector: IPEX</li><li>PA Output: 28 dBm (FCC), 20 dBm (CE) / 630 mW (FCC), 100 mW (CE)</li><li>Wi-Fi Chip: Runcam custom RTL8812EU (5, 10, 20 MHz)</li><li>UART: 1</li><li>SoC: SigmaStar SSC338Q</li><li>Firmware: <code>ssc338q_fpv_openipc_urllc_aio_nor.tgz</code> (<a href="https://docs.openipc.org/hardware/runcam/vtx/runcam-wifilink-v2/" target="_blank" rel="noreferrer">docs.openipc.org</a>)</li></ul><h3 id="board-layout" tabindex="-1">Board Layout <a class="header-anchor" href="#board-layout" aria-label="Permalink to &quot;Board Layout&quot;">​</a></h3><p><img src="https://raw.githubusercontent.com/OpenIPC/docs/refs/heads/main/src/assets/images/runcam-wifilink-2-motherboard-down-dark.png" alt="Board layout bottom 1"><img src="https://raw.githubusercontent.com/OpenIPC/docs/refs/heads/main/src/assets/images/runcam-wifilink-2-motherboard-up-dark.png" alt="Board layout bottom 2"></p><h3 id="basic-setup" tabindex="-1">Basic Setup <a class="header-anchor" href="#basic-setup" aria-label="Permalink to &quot;Basic Setup&quot;">​</a></h3><h3 id="required-components" tabindex="-1">Required Components <a class="header-anchor" href="#required-components" aria-label="Permalink to &quot;Required Components&quot;">​</a></h3><ul><li>Flight controller with Betaflight, INAV or Ardupilot firmware</li><li>Runcam WiFiLink 2 and the <a href="https://github.com/openipc/pixelpilot" target="_blank" rel="noreferrer">PixelPilot</a> app</li><li>RTL8812AU Wi-Fi adapter (included with WiFiLink2-G)</li><li>USB-C OTG adapter (included with WiFiLink2-G)</li><li>Android 13 or 14 smartphone with a powerful CPU</li><li>Internet connection (<a href="https://docs.openipc.org/hardware/runcam/vtx/runcam-wifilink-v2/" target="_blank" rel="noreferrer">docs.openipc.org</a>)</li></ul><h3 id="hardware-connection" tabindex="-1">Hardware Connection <a class="header-anchor" href="#hardware-connection" aria-label="Permalink to &quot;Hardware Connection&quot;">​</a></h3><ol><li>Attach the antennas to the VTX.</li><li>Connect the 4-pin cable to the UART on the FC (or solder directly), powering from the FC BEC; verify GND↔GND, VCC↔VCC.</li><li>Insert a formatted microSD card into the slot on the bottom of the VTX (fan on top).</li><li>Connect the included Ethernet cable to the device. (<a href="https://docs.openipc.org/hardware/runcam/vtx/runcam-wifilink-v2/" target="_blank" rel="noreferrer">docs.openipc.org</a>)</li></ol><h3 id="getting-the-gs-key-file" tabindex="-1">Getting the <code>gs.key</code> File <a class="header-anchor" href="#getting-the-gs-key-file" aria-label="Permalink to &quot;Getting the `gs.key` File&quot;">​</a></h3><ol><li>Insert an empty, formatted microSD card into the VTX (contacts facing the board); disassemble the housing if needed.</li><li>On first boot the device will create <code>user</code> and <code>gs.key</code>; copy <code>gs.key</code> to your VRX (Android, PC, etc.). (<a href="https://docs.openipc.org/hardware/runcam/vtx/runcam-wifilink-v2/" target="_blank" rel="noreferrer">docs.openipc.org</a>)</li></ol><h3 id="connecting-to-android-ground-station" tabindex="-1">Connecting to Android Ground Station <a class="header-anchor" href="#connecting-to-android-ground-station" aria-label="Permalink to &quot;Connecting to Android Ground Station&quot;">​</a></h3><ol><li>Install <a href="https://github.com/openipc/pixelpilot" target="_blank" rel="noreferrer">PixelPilot</a>.</li><li>Copy <code>gs.key</code> to your Android device.</li><li>Connect the RTL8812AU Wi-Fi adapter to Android.</li><li>Open PixelPilot via the pop-up.</li><li>Tap the gear icon and set: Channel – 161; Bandwidth – 20.</li><li>Add <code>gs.key</code>: Gear → WFB-NG → gs.key → select the copied file.</li><li>Power on the VTX.</li><li>If video does not appear within 30 seconds, restart PixelPilot. If the issue persists: <ul><li>Check the lens cap</li><li>Verify <code>gs.key</code></li><li>Restart Android and the VTX (<a href="https://docs.openipc.org/hardware/runcam/vtx/runcam-wifilink-v2/" target="_blank" rel="noreferrer">docs.openipc.org</a>)</li></ul></li></ol><h3 id="led-status" tabindex="-1">LED Status <a class="header-anchor" href="#led-status" aria-label="Permalink to &quot;LED Status&quot;">​</a></h3><table tabindex="0"><thead><tr><th>LED State</th><th>Meaning</th></tr></thead><tbody><tr><td>Green off</td><td>Audio disabled</td></tr><tr><td>Green on</td><td>Audio enabled</td></tr><tr><td>Green fast blinking</td><td>Firmware update</td></tr><tr><td>Green slow blinking</td><td>Recording</td></tr><tr><td>Blue on</td><td>Booting</td></tr><tr><td>Blue fast blinking</td><td>Wi-Fi error</td></tr><tr><td>Blue and green alternating</td><td>Warning: overheating (&gt; 90 °C)</td></tr></tbody></table><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>After basic setup you will have a modern digital FPV system, but without OSD. To configure OSD see the <a href="/en/configuration/advanced">Advanced Settings guide</a>. For manufacturer instructions see the <a href="https://store-m8o52p.mybigcommerce.com" target="_blank" rel="noreferrer">official documentation</a>.</p>',19)])])}const m=t(r,[["render",o]]);export{u as __pageData,m as default};
